 21→// handleCreateInstance creates a new KlausInstance for the calling user.
 22→func (s *Server) handleCreateInstance(ctx context.Context, request mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
 23→	user, err := s.extractUser(ctx)
 24→	if err != nil {
 25→		return mcpError("authentication required: " + err.Error()), nil
 26→	}
 27→
 28→	args := request.GetArguments()
 29→
 30→	name, _ := args["name"].(string)
 31→	if name == "" {
 32→		return mcpError("name is required"), nil
 33→	}
 34→
 35→	model, _ := args["model"].(string)
 36→	if model == "" {
 37→		model = "claude-sonnet-4-20250514"
 38→	}
 39→
 40→	systemPrompt, _ := args["system_prompt"].(string)
 41→	personality, _ := args["personality"].(string)
 42→
 43→	instance := &klausv1alpha1.KlausInstance{
 44→		ObjectMeta: metav1.ObjectMeta{
 45→			Name:      name,
 46→			Namespace: s.operatorNamespace,
 47→		},
 48→		Spec: klausv1alpha1.KlausInstanceSpec{
 49→			Owner: user,
 50→			Claude: klausv1alpha1.ClaudeConfig{
 51→				Model:          model,
 52→				PermissionMode: klausv1alpha1.PermissionModeBypass,
 53→				SystemPrompt:   systemPrompt,
 54→			},
 55→		},
 56→	}
 57→
 58→	if personality != "" {
 59→		instance.Spec.Personality = personality
 60→	}
 61→
 62→	if err := s.client.Create(ctx, instance); err != nil {
 63→		if apierrors.IsAlreadyExists(err) {
 64→			return mcpError("instance '" + name + "' already exists"), nil
 65→		}
 66→		return mcpError("failed to create instance: " + err.Error()), nil
 67→	}
 68→
 69→	return mcpSuccess(map[string]any{
 70→		"name":      name,
 71→		"owner":     user,
 72→		"model":     model,
 73→		"namespace": resources.UserNamespace(user),
 74→		"status":    "creating",
 75→	}), nil
 76→}
