 78→// handleListInstances lists the calling user's instances.
 79→func (s *Server) handleListInstances(ctx context.Context, _ mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
 80→	user, err := s.extractUser(ctx)
 81→	if err != nil {
 82→		return mcpError("authentication required: " + err.Error()), nil
 83→	}
 84→
 85→	var instanceList klausv1alpha1.KlausInstanceList
 86→	if err := s.client.List(ctx, &instanceList, client.InNamespace(s.operatorNamespace)); err != nil {
 87→		return mcpError("failed to list instances: " + err.Error()), nil
 88→	}
 89→
 90→	var userInstances []map[string]any
 91→	for _, inst := range instanceList.Items {
 92→		if inst.Spec.Owner != user {
 93→			continue
 94→		}
 95→		userInstances = append(userInstances, map[string]any{
 96→			"name":        inst.Name,
 97→			"state":       string(inst.Status.State),
 98→			"endpoint":    inst.Status.Endpoint,
 99→			"mode":        inst.Status.Mode,
100→			"personality": inst.Status.Personality,
101→			"plugins":     inst.Status.PluginCount,
102→			"mcpServers":  inst.Status.MCPServerCount,
103→			"age":         time.Since(inst.CreationTimestamp.Time).Truncate(time.Second).String(),
104→		})
105→	}
106→
107→	return mcpSuccess(map[string]any{
108→		"owner":     user,
109→		"count":     len(userInstances),
110→		"instances": userInstances,
111→	}), nil
112→}
