114→// handleDeleteInstance deletes a KlausInstance (owner-only).
115→func (s *Server) handleDeleteInstance(ctx context.Context, request mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
116→	instance, errResult := s.getOwnedInstance(ctx, request)
117→	if errResult != nil {
118→		return errResult, nil
119→	}
120→
121→	if err := s.client.Delete(ctx, instance); err != nil {
122→		return mcpError("failed to delete instance: " + err.Error()), nil
123→	}
124→
125→	return mcpSuccess(map[string]any{
126→		"name":    instance.Name,
127→		"status":  "deleting",
128→		"message": "Instance '" + instance.Name + "' is being deleted",
129→	}), nil
130→}
