132→// handleGetInstance returns details about a KlausInstance.
133→func (s *Server) handleGetInstance(ctx context.Context, request mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
134→	instance, errResult := s.getOwnedInstance(ctx, request)
135→	if errResult != nil {
136→		return errResult, nil
137→	}
138→
139→	result := map[string]any{
140→		"name":        instance.Name,
141→		"owner":       instance.Spec.Owner,
142→		"state":       string(instance.Status.State),
143→		"endpoint":    instance.Status.Endpoint,
144→		"mode":        instance.Status.Mode,
145→		"model":       instance.Spec.Claude.Model,
146→		"personality": instance.Status.Personality,
147→		"plugins":     instance.Status.PluginCount,
148→		"mcpServers":  instance.Status.MCPServerCount,
149→		"created":     instance.CreationTimestamp.Format(time.RFC3339),
150→		"namespace":   resources.UserNamespace(instance.Spec.Owner),
151→	}
152→
153→	if instance.Status.Toolchain != "" {
154→		result["toolchain"] = instance.Status.Toolchain
155→	}
156→
157→	if instance.Status.LastActivity != nil {
158→		result["lastActivity"] = instance.Status.LastActivity.Format(time.RFC3339)
159→	}
160→
161→	return mcpSuccess(result), nil
162→}
