164→// handleRestartInstance restarts a KlausInstance by cycling its Deployment.
165→func (s *Server) handleRestartInstance(ctx context.Context, request mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
166→	instance, errResult := s.getOwnedInstance(ctx, request)
167→	if errResult != nil {
168→		return errResult, nil
169→	}
170→
171→	// Restart by patching the Deployment with a restart annotation.
172→	namespace := resources.UserNamespace(instance.Spec.Owner)
173→	var deployment appsv1.Deployment
174→	if err := s.client.Get(ctx, types.NamespacedName{
175→		Name:      instance.Name,
176→		Namespace: namespace,
177→	}, &deployment); err != nil {
178→		if apierrors.IsNotFound(err) {
179→			return mcpError("deployment for instance '" + instance.Name + "' not found (instance may still be starting)"), nil
180→		}
181→		return mcpError("failed to get deployment: " + err.Error()), nil
182→	}
183→
184→	// Use a strategic merge patch to avoid conflicts with the controller's
185→	// concurrent reconciliation of the same Deployment object.
186→	patch := client.MergeFrom(deployment.DeepCopy())
187→	if deployment.Spec.Template.Annotations == nil {
188→		deployment.Spec.Template.Annotations = map[string]string{}
189→	}
190→	deployment.Spec.Template.Annotations["kubectl.kubernetes.io/restartedAt"] = time.Now().Format(time.RFC3339)
191→
192→	if err := s.client.Patch(ctx, &deployment, patch); err != nil {
193→		return mcpError("failed to restart deployment: " + err.Error()), nil
194→	}
195→
196→	return mcpSuccess(map[string]any{
197→		"name":    instance.Name,
198→		"status":  "restarting",
199→		"message": "Instance '" + instance.Name + "' is being restarted",
200→	}), nil
201→}
