203→// getOwnedInstance extracts the user and instance name from a tool request,
204→// fetches the KlausInstance, and verifies ownership. Returns the instance on
205→// success, or an MCP error result on failure.
206→func (s *Server) getOwnedInstance(ctx context.Context, request mcpgolang.CallToolRequest) (*klausv1alpha1.KlausInstance, *mcpgolang.CallToolResult) {
207→	user, err := s.extractUser(ctx)
208→	if err != nil {
209→		return nil, mcpError("authentication required: " + err.Error())
210→	}
211→
212→	args := request.GetArguments()
213→	name, _ := args["name"].(string)
214→	if name == "" {
215→		return nil, mcpError("name is required")
216→	}
217→
218→	var instance klausv1alpha1.KlausInstance
219→	if err := s.client.Get(ctx, types.NamespacedName{
220→		Name:      name,
221→		Namespace: s.operatorNamespace,
222→	}, &instance); err != nil {
223→		if apierrors.IsNotFound(err) {
224→			return nil, mcpError("instance '" + name + "' not found")
225→		}
226→		return nil, mcpError("failed to get instance: " + err.Error())
227→	}
228→
229→	if instance.Spec.Owner != user {
230→		return nil, mcpError("access denied: you do not own instance '" + name + "'")
231→	}
232→
233→	return &instance, nil
234→}
