236→// extractUser extracts the user identity from the request context.
237→// The Authorization header is injected into context by HTTPContextFuncAuth via
238→// mcp-go's WithHTTPContextFunc. The token is a JWT forwarded by muster.
239→func (s *Server) extractUser(ctx context.Context) (string, error) {
240→	token := AuthTokenFromContext(ctx)
241→	if token == "" {
242→		return "", fmt.Errorf("no Authorization header in request")
243→	}
244→	return ExtractUserFromToken(token)
245→}
