247→func mcpSuccess(data any) *mcpgolang.CallToolResult {
248→	jsonBytes, err := json.MarshalIndent(data, "", "  ")
249→	if err != nil {
250→		return mcpError("failed to marshal response: " + err.Error())
251→	}
252→	return &mcpgolang.CallToolResult{
253→		Content: []mcpgolang.Content{
254→			mcpgolang.NewTextContent(string(jsonBytes)),
255→		},
256→	}
257→}
