283→func (s *Server) listEntries(ctx context.Context, listFn func(context.Context, ...klausoci.ListOption) ([]klausoci.ListEntry, error), kind string) (*mcpgolang.CallToolResult, error) {
284→	entries, err := listFn(ctx)
285→	if err != nil {
286→		return mcpError(fmt.Sprintf("failed to list %s: %s", kind, err.Error())), nil
287→	}
288→
289→	items := make([]map[string]any, 0, len(entries))
290→	for _, e := range entries {
291→		item := map[string]any{
292→			"name":       e.Name,
293→			"repository": e.Repository,
294→			"reference":  e.Reference,
295→		}
296→		if e.Version != "" {
297→			item["version"] = e.Version
298→		}
299→		items = append(items, item)
300→	}
301→
302→	return mcpSuccess(map[string]any{
303→		"kind":  kind,
304→		"count": len(items),
305→		"items": items,
306→	}), nil
307→}
