309→func mcpError(msg string) *mcpgolang.CallToolResult {
310→	return &mcpgolang.CallToolResult{
311→		Content: []mcpgolang.Content{
312→			mcpgolang.NewTextContent(msg),
313→		},
314→		IsError: true,
315→	}
316→}
