12→// contextKey is a private type for context keys in this package.
13→type contextKey int
14→
15→const (
16→	// authTokenKey is the context key for the Authorization header value.
17→	authTokenKey contextKey = iota
18→)
19→
20→// HTTPContextFuncAuth extracts the Authorization header from the incoming HTTP
21→// request and stores it in the context. It is used with mcp-go's
22→// WithHTTPContextFunc to make the token available to tool handlers.
23→func HTTPContextFuncAuth(ctx context.Context, r *http.Request) context.Context {
24→	if token := r.Header.Get("Authorization"); token != "" {
25→		ctx = context.WithValue(ctx, authTokenKey, token)
26→	}
27→	return ctx
28→}
29→
30→// AuthTokenFromContext retrieves the Authorization header value stored in the
31→// context by HTTPContextFuncAuth.
32→func AuthTokenFromContext(ctx context.Context) string {
33→	if token, ok := ctx.Value(authTokenKey).(string); ok {
34→		return token
35→	}
36→	return ""
37→}
38→
39→// ExtractUserFromToken extracts the user identity (email or subject) from a
40→// JWT token forwarded by muster. This does not verify the token -- verification
41→// is handled by muster before forwarding.
42→func ExtractUserFromToken(token string) (string, error) {
43→	if token == "" {
44→		return "", fmt.Errorf("no token provided")
45→	}
46→
47→	// Strip "Bearer " prefix (case-insensitive per RFC 6750).
48→	if len(token) > 7 && strings.EqualFold(token[:7], "bearer ") {
49→		token = token[7:]
50→	}
51→
52→	// JWT has three parts separated by dots.
53→	parts := strings.Split(token, ".")
54→	if len(parts) != 3 {
55→		return "", fmt.Errorf("invalid JWT format: expected 3 parts, got %d", len(parts))
56→	}
57→
58→	// Decode the payload (second part).
59→	payload, err := base64.RawURLEncoding.DecodeString(parts[1])
60→	if err != nil {
61→		return "", fmt.Errorf("decoding JWT payload: %w", err)
62→	}
63→
64→	// Parse claims.
65→	var claims struct {
66→		Email   string `json:"email"`
67→		Subject string `json:"sub"`
68→	}
69→	if err := json.Unmarshal(payload, &claims); err != nil {
70→		return "", fmt.Errorf("parsing JWT claims: %w", err)
71→	}
72→
73→	// Prefer email, fall back to subject.
74→	if claims.Email != "" {
75→		return claims.Email, nil
76→	}
77→	if claims.Subject != "" {
78→		return claims.Subject, nil
79→	}
80→
81→	return "", fmt.Errorf("JWT contains neither email nor sub claim")
82→}
