167→// handleRestartInstance restarts a KlausInstance by cycling its Deployment.
168→func (s *Server) handleRestartInstance(ctx context.Context, request mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
169→	instance, errResult := s.getOwnedInstance(ctx, request)
170→	if errResult != nil {
171→		return errResult, nil
172→	}
173→
174→	// Restart by patching the Deployment with a restart annotation.
175→	namespace := resources.UserNamespace(instance.Spec.Owner)
176→	var deployment appsv1.Deployment
177→	if err := s.client.Get(ctx, types.NamespacedName{
178→		Name:      instance.Name,
179→		Namespace: namespace,
180→	}, &deployment); err != nil {
181→		if apierrors.IsNotFound(err) {
182→			return mcpError("deployment for instance '" + instance.Name + "' not found (instance may still be starting)"), nil
183→		}
184→		return mcpError("failed to get deployment: " + err.Error()), nil
185→	}
186→
187→	// Use a strategic merge patch to avoid conflicts with the controller's
188→	// concurrent reconciliation of the same Deployment object.
189→	patch := client.MergeFrom(deployment.DeepCopy())
190→	if deployment.Spec.Template.Annotations == nil {
191→		deployment.Spec.Template.Annotations = map[string]string{}
192→	}
193→	deployment.Spec.Template.Annotations["kubectl.kubernetes.io/restartedAt"] = time.Now().Format(time.RFC3339)
194→
195→	if err := s.client.Patch(ctx, &deployment, patch); err != nil {
196→		return mcpError("failed to restart deployment: " + err.Error()), nil
197→	}
198→
199→	return mcpSuccess(map[string]any{
200→		"name":    instance.Name,
201→		"status":  "restarting",
202→		"message": "Instance '" + instance.Name + "' is being restarted",
203→	}), nil
204→}
