302→// extractUser extracts the user identity from the request context.
303→// The Authorization header is injected into context by HTTPContextFuncAuth via
304→// mcp-go's WithHTTPContextFunc. The token is a JWT forwarded by muster.
305→func (s *Server) extractUser(ctx context.Context) (string, error) {
306→	token := AuthTokenFromContext(ctx)
307→	if token == "" {
308→		return "", fmt.Errorf("no Authorization header in request")
309→	}
310→	return ExtractUserFromToken(token)
311→}
312→
313→func mcpSuccess(data any) *mcpgolang.CallToolResult {
314→	jsonBytes, err := json.MarshalIndent(data, "", "  ")
315→	if err != nil {
316→		return mcpError("failed to marshal response: " + err.Error())
317→	}
318→	return &mcpgolang.CallToolResult{
319→		Content: []mcpgolang.Content{
320→			mcpgolang.NewTextContent(string(jsonBytes)),
321→		},
322→	}
323→}
