326→func (s *Server) handleListPlugins(ctx context.Context, _ mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
327→	if s.ociClient == nil {
328→		return mcpError("OCI client not configured"), nil
329→	}
330→	return s.listEntries(ctx, s.ociClient.ListPlugins, "plugins")
331→}
