333→// handleListPersonalities lists available Klaus personalities from the OCI registry.
334→func (s *Server) handleListPersonalities(ctx context.Context, _ mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
335→	if s.ociClient == nil {
336→		return mcpError("OCI client not configured"), nil
337→	}
338→	return s.listEntries(ctx, s.ociClient.ListPersonalities, "personalities")
339→}
