341→// handleListToolchains lists available Klaus toolchain images from the OCI registry.
342→func (s *Server) handleListToolchains(ctx context.Context, _ mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
343→	if s.ociClient == nil {
344→		return mcpError("OCI client not configured"), nil
345→	}
346→	return s.listEntries(ctx, s.ociClient.ListToolchains, "toolchains")
347→}
348→
349→func (s *Server) listEntries(ctx context.Context, listFn func(context.Context, ...klausoci.ListOption) ([]klausoci.ListEntry, error), kind string) (*mcpgolang.CallToolResult, error) {
350→	entries, err := listFn(ctx)
351→	if err != nil {
352→		return mcpError(fmt.Sprintf("failed to list %s: %s", kind, err.Error())), nil
353→	}
354→
355→	items := make([]map[string]any, 0, len(entries))
356→	for _, e := range entries {
357→		item := map[string]any{
358→			"name":       e.Name,
359→			"repository": e.Repository,
360→			"reference":  e.Reference,
361→		}
362→		if e.Version != "" {
363→			item["version"] = e.Version
364→		}
365→		items = append(items, item)
366→	}
367→
368→	return mcpSuccess(map[string]any{
369→		"kind":  kind,
370→		"count": len(items),
371→		"items": items,
372→	}), nil
373→}
374→
375→func mcpError(msg string) *mcpgolang.CallToolResult {
376→	return &mcpgolang.CallToolResult{
377→		Content: []mcpgolang.Content{
378→			mcpgolang.NewTextContent(msg),
379→		},
380→		IsError: true,
381→	}
382→}
