206→// handleGetLogs retrieves recent log output from a Klaus instance pod.
207→func (s *Server) handleGetLogs(ctx context.Context, request mcpgolang.CallToolRequest) (*mcpgolang.CallToolResult, error) {
208→	instance, errResult := s.getOwnedInstance(ctx, request)
209→	if errResult != nil {
210→		return errResult, nil
211→	}
212→
213→	args := request.GetArguments()
214→
215→	// Parse optional tail parameter (default 100).
216→	var tailLines int64 = 100
217→	if v, ok := args["tail"].(float64); ok && v > 0 {
218→		tailLines = int64(v)
219→	}
220→
221→	// Parse optional container parameter (default "klaus").
222→	container := "klaus"
223→	if v, _ := args["container"].(string); v != "" {
224→		container = v
225→	}
226→
227→	// Find pods matching the instance in the user namespace.
228→	namespace := resources.UserNamespace(instance.Spec.Owner)
229→	var podList corev1.PodList
230→	sel := labels.SelectorFromSet(resources.SelectorLabels(instance))
231→	if err := s.client.List(ctx, &podList, client.InNamespace(namespace), client.MatchingLabelsSelector{Selector: sel}); err != nil {
232→		return mcpError("failed to list pods: " + err.Error()), nil
233→	}
234→
235→	if len(podList.Items) == 0 {
236→		return mcpError("no pods found for instance '" + instance.Name + "' (instance may still be starting)"), nil
237→	}
238→
239→	pod := podList.Items[0]
240→
241→	// Read logs via the PodLogReader interface.
242→	if s.podLogReader == nil {
243→		return mcpError("pod log reader not configured"), nil
244→	}
245→
246→	logOpts := &corev1.PodLogOptions{
247→		Container: container,
248→		TailLines: &tailLines,
249→	}
250→
251→	stream, err := s.podLogReader.GetLogs(ctx, namespace, pod.Name, logOpts)
252→	if err != nil {
253→		return mcpError(fmt.Sprintf("failed to get logs for container %q: %v", container, err)), nil
254→	}
255→	defer stream.Close()
256→
257→	logBytes, err := io.ReadAll(stream)
258→	if err != nil {
259→		return mcpError("failed to read log stream: " + err.Error()), nil
260→	}
261→
262→	return &mcpgolang.CallToolResult{
263→		Content: []mcpgolang.Content{
264→			mcpgolang.NewTextContent(string(logBytes)),
265→		},
266→	}, nil
267→}
