269→// getOwnedInstance extracts the user and instance name from a tool request,
270→// fetches the KlausInstance, and verifies ownership. Returns the instance on
271→// success, or an MCP error result on failure.
272→func (s *Server) getOwnedInstance(ctx context.Context, request mcpgolang.CallToolRequest) (*klausv1alpha1.KlausInstance, *mcpgolang.CallToolResult) {
273→	user, err := s.extractUser(ctx)
274→	if err != nil {
275→		return nil, mcpError("authentication required: " + err.Error())
276→	}
277→
278→	args := request.GetArguments()
279→	name, _ := args["name"].(string)
280→	if name == "" {
281→		return nil, mcpError("name is required")
282→	}
283→
284→	var instance klausv1alpha1.KlausInstance
285→	if err := s.client.Get(ctx, types.NamespacedName{
286→		Name:      name,
287→		Namespace: s.operatorNamespace,
288→	}, &instance); err != nil {
289→		if apierrors.IsNotFound(err) {
290→			return nil, mcpError("instance '" + name + "' not found")
291→		}
292→		return nil, mcpError("failed to get instance: " + err.Error())
293→	}
294→
295→	if instance.Spec.Owner != user {
296→		return nil, mcpError("access denied: you do not own instance '" + name + "'")
297→	}
298→
299→	return &instance, nil
300→}
